var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"후우...... 아슬아슬했네.","JPN":"ふぅ……危なかったな。","ENG":"Phew... That was close.","TWN":"呼……有驚無險。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"수고했어, 플루토. 상으로 돌아가서 털손질 해 줄게.","JPN":"お疲れ様、プルートー。ご褒美に毛を手入れしてやるよ。","ENG":"Well done, Pluto. I'll brush your fur when we get back as a reward.","TWN":"辛苦了，布魯托。回去後我幫你修一下毛。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"야옹~","JPN":"にゃあ～","ENG":"Meow!","TWN":"喵喵~"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"후후후, 한순간이나마 이 몸을 긴장하게 만들다니 제법이었다. 제 3종 침식체.","JPN":"ふふふ、一瞬だったけどこの私を緊張させるなんてやるじゃない。第3種侵食体。","ENG":"Hah hah, I'm impressed, Category 3. You actually got me a little nervous back there.","TWN":"吼吼吼，能讓我這麼緊張，不愧是3類侵蝕體。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그 달달 떨리는 다리에 힘이나 주고 말하지 그래?","JPN":"そのブルブル震える脚を落ち着かせてから言ったらどうだ？","ENG":"A little nervous? Your legs are still shaking.","TWN":"妳倒是好好管管妳那抖個不停的腿吧。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"이, 이건 떠는 게 아니라 긴장을 풀기 위한 스트레칭이라고!","JPN":"ふ、震えてるんじゃなくて、緊張を和らげるためのストレッチングよ！","ENG":"I'm not shaking! I'm just trying to work off the tension!","TWN":"這、這不是抖，這是為了緩解緊張的熱身運動！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗. 그나저나 우리 유나, 굉장하던데?","JPN":"ふふっ。ところでユナ、すごいじゃない。","ENG":"Hah hah. Anyway, that was pretty impressive of you, Yuna.","TWN":"呼，尤娜，妳真是了不起啊？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네? 제가요?","JPN":"え？　私ですか？","ENG":"Huh? Me?","TWN":"什麼？我嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그래. <color=#ffd34c>인형</color>은 원래 쉽게 쓰러트릴 수 있는 상대가 아니거든.","JPN":"そうよ。<color=#ffd34c>人形</color>ってそう簡単に倒せる相手じゃないの。","ENG":"That's right. <color=#ffd34c>Puppets</color> are not that easy to take down.","TWN":"對啊。<color=#ffd34c>木偶</color>可不是輕而易舉就可以打敗的。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그런데 전투 중에 네가 날린 화염구를 맞은 뒤로는 꼭 실 끊어진 꼭두각시처럼 허우적대기만 하던걸?","JPN":"でも戦闘中にあなたの火の玉に当たってからは、糸が切れた操り人形みたいにバタバタしてたわ！","ENG":"But they waddled about like marionettes without their strings after one of your fireballs hit them.","TWN":"但在戰鬥的時候，木偶被你的火焰球擊中後就只能無力的掙扎了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"제가 그랬어요......?","JPN":"私そんなことしましたっけ……？","ENG":"I did that?","TWN":"我嗎……？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"헤헤, 도망 다니느라 정신이 없어서 잘 모르겠어요.","JPN":"えヘヘ、逃げるのに夢中でよく覚えてないんです。","ENG":"Heh heh, to be honest, I had no idea because I was so busy running.","TWN":"嘿嘿，我就顧著逃跑了，還真沒注意到。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼. 역시 메이 할머니의 손녀야. 자신감을 가져도 돼.","JPN":"うん。さすがメイお婆ちゃんの孫娘ね。自信を持っていいわ。","ENG":"You sure did. You really must take after Granny May. Have a little more confidence.","TWN":"嗯，果然是梅伊奶奶的孫女，要對自己有信心。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"덕분에 다친 사람 없이 큰 수확까지 얻었잖니.","JPN":"おかげで怪我人もなく、大きな収穫を得られたからね。","ENG":"Thanks to you, nobody got hurt and we got some extra goodies.","TWN":"多虧了妳，都沒有人受傷，收獲很不錯。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"수확이요?","JPN":"収穫？","ENG":"Goodies?","TWN":"收獲？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"발푸르기스의 인형들은 아주 강력한 마법의 재료들로 만들어져 있거든.","JPN":"ヴァルプルギスの人形って、とても強力な魔法の材料でできてるの。","ENG":"Walpurgis puppets are made of extremely potent magic materials.","TWN":"魔女之夜城的木偶是用非常強大的魔法材料製成的。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"할로윈 코스튬에 이것들을 섞어 만들면 효과가 훨씬 더 좋아질 거야.","JPN":"ハロウィンコスチュームにこれを混ぜて作れば、もっと効果が高くなるはずよ。","ENG":"If we mix these in with the Halloween costumes, they'll be even more effective.","TWN":"在萬聖節服裝裡添加這些材料效果會更好。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"오오! 그거 멋진데?!","JPN":"おお！　いいね、それ！","ENG":"Ooh, that sounds neat!","TWN":"哦！這麼棒？！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그래. 그러니까 더 늦기 전에 얼른 나가자.","JPN":"そう。だから遅くなる前に早くここを出ましょう。","ENG":"Yeah, so let's get out of here before it's too late.","TWN":"嗯，我們趕快出去吧。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"돌아가서도 해야 할 일이 산더미 같거든.","JPN":"帰ってからもやることが山積みだしね。","ENG":"We still got piles of work when we get back.","TWN":"外面還有一堆事等著我們呢。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"좋았어! 순식간에 시험 통과하고 정식 마녀가 되야지!","JPN":"よっしゃ！　一発で試験に合格して正式な魔女になる！","ENG":"Alright! I'll pass this test in a breeze and finally become an official witch!","TWN":"好！我一定會立馬通過考試，然後成為正式魔女！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"또 뭐 해? 빨리 안 따라오고.","JPN":"何してるんだ？　早くついてこい。","ENG":"What are you waiting for? Come along now.","TWN":"又在幹嘛？快跟上。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아, 지금 가요!","JPN":"い、今行きます！","ENG":"Oh, coming!","TWN":"啊，來了！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"아아, 주인님......","JPN":"ああ、ご主人様……","ENG":"Oh, Master...","TWN":"啊，主人……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"이 비굴하고 어리석은 몸에...... 당신의 고통을 새겨 주시기를......","JPN":"この卑屈で愚かな体に……あなたの苦痛をお刻みください……","ENG":"Ingrain this foolish, wretched flesh with the pangs of your agony...","TWN":"請在我這卑怯愚蠢的身體……刻上您的痛苦吧……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"뼛속 깊이 스며들어, 영혼마저 타 들어가는 고통으로 당신을 숭배할 수 있게......","JPN":"骨身に染みて、魂まで燃え尽きる苦痛であなたを崇拝できるように……","ENG":"May the pain seep deep into my bones, so that I may worship you in agony as my soul writhes in flames...","TWN":"讓它滲入我的內心深處，讓我用以痛苦焚燒的靈魂來崇拜您吧……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"태양의 불길보다 뜨겁게 타오르는 희열 속에서, 녹아내릴 수 있게......","JPN":"太陽の炎より熱く燃え上がる喜びの中で、溶けてしまうように……","ENG":"May I melt in the fiery ecstasy that burns brighter than the sun...","TWN":"望它在比太陽之火燃燒的更火熱的喜悅中融化…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"아아, 주인님......","JPN":"ああ、ご主人様……","ENG":"Oh, Master...","TWN":"啊，主人……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"오직 당신께서 내려 주실 고통만을...... 기다리고 있나이다......","JPN":"ただあなたが与えてくださる苦痛だけを……待っております……","ENG":"I await the suffering... that only you can bestow upon me...","TWN":"我等待的……只是您賜予我的痛苦啊……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};